import { GeoBubbleSeries } from './geo-bubble';
import { isDataActive } from '../core/data-processor/is-data-active';
import { bubbleSelection } from '../scatter/bubbleSelection';
import { getGeoEnclosedPoints } from '../geo-core/zc_map_events';

/**
 *
 * @param latLong
 * @param mousePosition
 * @param skipColorRangeCheck
 * @return {*}
 */
GeoBubbleSeries.prototype.getPoint = function(latLong, mousePosition, skipColorRangeCheck) {
    var series = this,
        geoMap = series.geoMap,
        dataObject = geoMap.dataObject,
        chartName = geoMap.chartTypes[series.index].name,
        flattenPoints = dataObject.flattenPoints.get(chartName);

    if (!flattenPoints) {
        return null;
    }

    let enclosed = getGeoEnclosedPoints(flattenPoints, 'geobubble', mousePosition, 'QUADTREE', geoMap);

    let point = bubbleSelection(enclosed, { x: mousePosition[0], y: mousePosition[1] }, geoMap, 'bubble');

    if (point) {
        if (skipColorRangeCheck || isDataActive(point, geoMap)) {
            return {
                type: 'point',
                point: point
            };
        }
    }

    return;
};

export var _geoBubbleEvent = GeoBubbleSeries.prototype;
